#include<bits/stdc++.h>
using namespace std;
int a[101][101],dp[2000010];
int main()
{
    int n,m,d;
    scanf("%d%d%d",&n,&d,&m);
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=d;j++)
        {
            scanf("%d",&a[i][j]);
        }
    }
    for(int i=1;i<d;i++)
    {
        memset(dp,0,sizeof(dp));
        for(int j=1;j<=n;j++)
        {
            for(int k=a[j][i];k<=m;k++)
            {
                dp[k]=max(dp[k],dp[k-a[j][i]]+a[j][i+1]-a[j][i]);
            }
        }
        m+=dp[m];
    }
    printf("%d",m);
    return 0;
}
